```bash
#!/bin/bash
watch -n 5 ''
cockroach node status --certs-dir=certs --host=localhost:26257
echo ""
cockroach sql --host=localhost:26257 --certs-dir=certs --execute="
  SET allow_unsafe_internals = true;
  SELECT
    count(*) FILTER (WHERE array_length(replicas, 1) < 3) AS under_replicated,
    count(*) AS total_ranges
  FROM crdb_internal.ranges;"
''
