INSERT INTO chunks (id, skill_id, section_title, content, chunk_index, embedding) VALUES (
  '857bf84b-6bf7-5a4e-87d1-9369a6d277ac',
  '6edefee9-fb98-553c-9a15-fe0a275f3b4e',
  'What This Skill Teaches',
  'This skill teaches you to safely perform rolling restarts across a CockroachDB cluster to execute maintenance operations (version upgrades, configuration changes, hardware maintenance) without causing service interruption or data unavailability. You''ll learn the complete drain-restart-verify cycle, understanding each phase of graceful shutdown and how to validate cluster health before proceeding to the next node.

CockroachDB''s architecture supports zero-downtime maintenance through live rolling upgrades and graceful node draining. When performed correctly, rolling restarts allow you to take down one node at a time while the cluster continues serving reads and writes from the remaining nodes.

**Key Concepts Covered**:
- Four-phase drain process (SQL wait, SQL drain, DistSQL drain, lease transfer)
- Node shutdown with `--shutdown` flag for automatic termination
- Health verification between restarts (node liveness, range availability, lease distribution)
- Drain timeouts and handling stalled lease transfers
- Safe termination practices (avoiding SIGKILL)',
  1,
