INSERT INTO chunks (id, skill_id, section_title, content, chunk_index, embedding) VALUES (
  'ea57cbcc-fb08-54b9-96b3-93af9189b004',
  '12064006-c71c-5a0b-9338-1c698d60e9d4',
  'Related Operations',
  '**vs Draining:**
- Drain: Temporary, for maintenance, reversible with restart
- Decommission: Permanent, for removal, irreversible

**vs Recommissioning:**
- Recommission: Cancels in-progress decommission, brings node back
- Only works before `membership` = `decommissioned`

**vs Stopping:**
- Decommission: Safely moves data away, then stop
- Stop: Immediate, data remains on stopped node',
