INSERT INTO chunks (id, skill_id, section_title, content, chunk_index, embedding) VALUES (
  'b92514b1-4b2a-504d-8c40-5aec1fd796eb',
  '1db6956e-7548-5ab7-b308-046fcaca70d3',
  'Overview',
  'Node draining is the process of **temporarily** removing a node from active service to perform maintenance. Unlike decommissioning (permanent removal with data migration), draining only transfers range **leases** and waits for in-flight operations to complete.

**Critical distinction:**
- **Drain**: Temporary, moves leases only, takes minutes, reversible with restart
- **Decommission**: Permanent, moves all replica data, takes hours, irreversible

Draining ensures zero dropped connections and minimal query disruption during maintenance operations.',
