INSERT INTO chunks (id, skill_id, section_title, content, chunk_index, embedding) VALUES (
  '3621112e-e797-5b88-a7a7-cb0dbafd7a18',
  '1db6956e-7548-5ab7-b308-046fcaca70d3',
  'How Draining Works',
  'When you drain a node, CockroachDB performs these phases in sequence:

### Phase 1: Unready Phase (Health Check Fails)
- Node starts returning HTTP 503 from `/health?ready=1` endpoint
- Load balancers detect unhealthy node and stop routing new connections
- Duration controlled by `server.shutdown.initial_wait` (default: 0s)
- Allows load balancer time to detect node unavailability

### Phase 2: Lease Transfer Phase
- All range leases transferred to other nodes
- No replica data moved (unlike decommission)
- Duration controlled by `server.shutdown.lease_transfer_wait` (default: 5s)
- Fast operation (seconds to minutes)

### Phase 3: SQL Connection Draining Phase
- New SQL connections rejected
- Existing connections allowed to close naturally
- Active queries allowed to complete
- Duration controlled by `--drain-wait` flag (default: 10m)
- Graceful shutdown without dropped connections

### Phase 4: Process Shutdown
- All phases complete successfully
- Node process can be stopped safely
- Node remains in cluster, can rejoin on restart

**Total drain time**: Typically 1-3 minutes for healthy nodes with normal traffic.',
  3,
