INSERT INTO chunks (id, skill_id, section_title, content, chunk_index, embedding) VALUES (
  '7721eba0-ecde-581e-952c-5f25d9e7d53c',
  '1db6956e-7548-5ab7-b308-046fcaca70d3',
  'Safety Rules',
  '1. **Never drain multiple nodes simultaneously** (risks quorum loss)
2. **Always verify cluster health before draining** (no under-replicated ranges)
3. **Wait for drain to complete** before stopping process
4. **Monitor drain progress actively** (don''t walk away)
5. **Set appropriate timeout** based on workload characteristics
6. **Remove from load balancer first** when possible
7. **Restart one node at a time** during rolling operations
8. **Test drain procedure in staging first** for production clusters',
  9,
