INSERT INTO chunks (id, skill_id, section_title, content, chunk_index, embedding) VALUES (
  'e711ce57-f6b0-52d0-b7f9-c79e933597ef',
  '1db6956e-7548-5ab7-b308-046fcaca70d3',
  'Best Practices',
  '1. **Configure load balancer health checks** to use `/health?ready=1` endpoint
2. **Set Kubernetes terminationGracePeriodSeconds** to 300s minimum
3. **Drain during low-traffic windows** when possible to minimize impact
4. **Use longer timeouts for critical workloads** (15-30 minutes)
5. **Monitor connection pools** to ensure they reconnect properly
6. **Document drain procedures** for your specific environment
7. **Automate rolling restarts** with proper drain sequencing
8. **Verify node rejoins successfully** after maintenance',
