INSERT INTO chunks (id, skill_id, section_title, content, chunk_index, embedding) VALUES (
  'dcc0c0cf-4a44-5008-ade5-7a88be61a33e',
  '1db6956e-7548-5ab7-b308-046fcaca70d3',
  'Drain vs Decommission Comparison',
  '| Aspect | Drain | Decommission |
|--------|-------|--------------|
| **Purpose** | Temporary maintenance | Permanent removal |
| **Duration** | Minutes (1-3 typical) | Hours (1-12+ hours) |
| **Data movement** | Leases only | All replica data |
| **Reversibility** | Restart brings back | Irreversible |
| **Impact** | Minimal (lease transfer) | Moderate (data migration) |
| **Use for** | Restarts, upgrades | Downsizing, hardware replacement |
| **Network traffic** | Low | High (GB-TB transferred) |
| **Cluster membership** | Remains in cluster | Removed from cluster |',
  11,
