INSERT INTO chunks (id, skill_id, section_title, content, chunk_index, embedding) VALUES (
  'd4f2bc25-f7f8-55ec-8f28-cff37be2fb0e',
  '1db6956e-7548-5ab7-b308-046fcaca70d3',
  'Summary',
  'Graceful node draining is essential for zero-downtime maintenance:
- ✅ Transfers leases away from node (no replica data movement)
- ✅ Waits for active queries to complete naturally
- ✅ Prevents new connections from routing to draining node
- ✅ Allows safe process shutdown without dropped connections
- ✅ Reversible with simple restart after maintenance
- ✅ Completes in minutes (vs hours for decommission)

**Golden Rule**: Always drain before stopping a node for maintenance.',
  13,
