INSERT INTO chunks (id, skill_id, section_title, content, chunk_index, embedding) VALUES (
  '60db42a5-58bf-5e03-a316-4709d3438f69',
  '367b6ffc-261d-5fd7-8f05-fd29fb08aa19',
  'Step 3: Restart Each Node Sequentially',
  'Perform complete restart procedure for each node.

### Single Node Restart Procedure

```bash
#!/bin/bash
NODE_ID=$1
NODE_HOST="node$NODE_ID"
HOST="localhost:26257"
CERTS_DIR="certs"

# Drain
cockroach node drain $NODE_ID --drain-wait=10m --host=$HOST --certs-dir=$CERTS_DIR || exit 1

# Stop
ssh $NODE_HOST "sudo systemctl stop cockroach"
sleep 5

# Perform maintenance (example: upgrade binary)
ssh $NODE_HOST "sudo cp /tmp/cockroach-new /usr/local/bin/cockroach"

# Start
ssh $NODE_HOST "sudo systemctl start cockroach"
sleep 15

# Verify health
until curl -sf http://$NODE_HOST:8080/health?ready=1 > /dev/null; do
  sleep 5
done

# Verify cluster membership
cockroach node status --host=$HOST --certs-dir=$CERTS_DIR --format=csv | \\
  grep -q "^$NODE_ID,.*true,true,false" || exit 1

# Wait for stabilization
sleep 30
echo "✅ Node $NODE_ID restart complete"
```

---

### Complete Rolling Restart Script

```bash
#!/bin/bash
set -e
HOST="localhost:26257"
CERTS_DIR="certs"
NODES=(1 2 3)

echo "Starting rolling restart at $(date)"

# Pre-flight checks
./pre-flight-check.sh || exit 1

# Restart each node
for NODE_ID in "${NODES[@]}"; do
  ./restart-single-node.sh $NODE_ID
  sleep 10
done

# Verify
cockroach node status --host=$HOST --certs-dir=$CERTS_DIR
echo "✅ Rolling restart complete"
```

---',
