INSERT INTO chunks (id, skill_id, section_title, content, chunk_index, embedding) VALUES (
  '1da8cb7c-a1dc-51c1-b922-fa5cf0e469e2',
  '367b6ffc-261d-5fd7-8f05-fd29fb08aa19',
  'Common Patterns',
  '### Pattern 1: Binary Upgrade Rolling Restart

```bash
#!/bin/bash
NODES=("node1" "node2" "node3")

# Set preserve downgrade
cockroach sql --host=localhost:26257 --certs-dir=certs --execute="
  SET CLUSTER SETTING cluster.preserve_downgrade_option = ''26.1'';"

# Distribute binary
for NODE in "${NODES[@]}"; do scp cockroach-v26.1.1 $NODE:/tmp/; done

# Rolling restart
for NODE in "${NODES[@]}"; do
  NODE_ID=$(echo $NODE | sed ''s/node//'')
  cockroach node drain $NODE_ID --host=localhost:26257 --certs-dir=certs
  ssh $NODE "sudo systemctl stop cockroach"
  ssh $NODE "sudo cp /tmp/cockroach-v26.1.1 /usr/local/bin/cockroach"
  ssh $NODE "sudo systemctl start cockroach"
  sleep 30
done

echo "✅ Upgrade complete. Finalize: RESET CLUSTER SETTING cluster.preserve_downgrade_option;"
```

---

### Pattern 2: Certificate Rotation Rolling Restart

```bash
#!/bin/bash
NODES=("node1" "node2" "node3")

for NODE in "${NODES[@]}"; do
  NODE_ID=$(echo $NODE | sed ''s/node//'')
  cockroach node drain $NODE_ID --host=localhost:26257 --certs-dir=certs
  ssh $NODE "sudo systemctl stop cockroach"
  ssh $NODE "sudo cp /tmp/new-certs/* /var/lib/cockroach/certs/"
  ssh $NODE "sudo chown cockroach:cockroach /var/lib/cockroach/certs/*"
  ssh $NODE "sudo systemctl start cockroach"
  sleep 30
done
echo "✅ Certificate rotation complete"
```

---',
