INSERT INTO chunks (id, skill_id, section_title, content, chunk_index, embedding) VALUES (
  '7a103502-49a7-5c97-b272-1f0d89c08dcc',
  '367b6ffc-261d-5fd7-8f05-fd29fb08aa19',
  'Important Notes',
  '⚠️ **One at a Time**: NEVER restart multiple nodes simultaneously. Always wait for one node to complete before starting next.

⚠️ **Verify Between Nodes**: Always verify node fully healthy and stabilized before moving to next node.

⚠️ **Minimum 3 Nodes**: Rolling restarts require ≥3 nodes. 2-node clusters risk quorum loss.

⚠️ **Replication Factor**: Ensure replication factor ≥3. Lower replication means data at risk during restart.

⚠️ **Monitor Throughout**: Watch cluster health continuously during rolling restart.

⚠️ **Have Rollback Plan**: For upgrades, be prepared to rollback if issues arise.

---',
  12,
