INSERT INTO chunks (id, skill_id, section_title, content, chunk_index, embedding) VALUES (
  '3a40e15b-89c3-5aef-8faa-22ab13e6e29e',
  '2a590116-b715-573c-a481-c647d9b0488e',
  'Complete 3-Node Upgrade Example',
  '### Scenario: v25.2.5 → v26.1.0

```bash
# === PREPARATION ===
# Set preserve_downgrade_option
cockroach sql --certs-dir=certs --execute="
  SET CLUSTER SETTING cluster.preserve_downgrade_option = ''25.2'';
"

# Verify
cockroach node status --certs-dir=certs
# All nodes on v25.2.5

# === NODE 1 ===
echo "Upgrading node 1..."
cockroach node drain 1 --certs-dir=certs --host=node1:26257
sudo systemctl stop cockroach  # on node1
sudo cp /opt/cockroach/bin/cockroach-v26.1.0 /usr/local/bin/cockroach  # on node1
sudo systemctl start cockroach  # on node1

# Verify
cockroach node status --certs-dir=certs
# Node 1 should show v26.1.0, is_live=true

# Wait 5 minutes
sleep 300

# === NODE 2 ===
echo "Upgrading node 2..."
cockroach node drain 2 --certs-dir=certs --host=node2:26257
sudo systemctl stop cockroach  # on node2
sudo cp /opt/cockroach/bin/cockroach-v26.1.0 /usr/local/bin/cockroach  # on node2
sudo systemctl start cockroach  # on node2

# Verify
cockroach node status --certs-dir=certs
# Nodes 1-2 should show v26.1.0

# Wait 5 minutes
sleep 300

# === NODE 3 ===
echo "Upgrading node 3..."
cockroach node drain 3 --certs-dir=certs --host=node3:26257
sudo systemctl stop cockroach  # on node3
sudo cp /opt/cockroach/bin/cockroach-v26.1.0 /usr/local/bin/cockroach  # on node3
sudo systemctl start cockroach  # on node3

# Verify all nodes upgraded
cockroach node status --certs-dir=certs
# All nodes show v26.1.0

# === FINALIZATION (later) ===
# After testing, finalize version
cockroach sql --certs-dir=certs --execute="
  SET CLUSTER SETTING version = ''26.1'';
"
```',
