INSERT INTO chunks (id, skill_id, section_title, content, chunk_index, embedding) VALUES (
  'bc672154-56f3-5e55-92e3-128178366959',
  '2a590116-b715-573c-a481-c647d9b0488e',
  'Rollback Before Finalization',
  '### If Issues Discovered

**Can rollback** if version not finalized:

```bash
# On each node (reverse order)
sudo systemctl stop cockroach
sudo cp /usr/local/bin/cockroach.v25.2 /usr/local/bin/cockroach
sudo systemctl start cockroach
```

**After finalization**: Rollback NOT possible',
  10,
