INSERT INTO chunks (id, skill_id, section_title, content, chunk_index, embedding) VALUES (
  '83fddbb8-bbb7-5e72-a4a1-de267902e9bd',
  '2a590116-b715-573c-a481-c647d9b0488e',
  'Best Practices',
  '1. **Set preserve_downgrade_option first** - enables rollback
2. **Upgrade during low-traffic period** - minimize impact
3. **One node at a time** - never multiple nodes
4. **Wait between nodes** - 5-10 minutes minimum
5. **Verify health before next node** - check ranges, liveness
6. **Keep old binary** - quick rollback if needed
7. **Monitor continuously** - watch metrics during upgrade
8. **Test thoroughly before finalization** - can''t rollback after
9. **Document the upgrade** - what happened, any issues
10. **Have rollback plan ready** - know exact steps',
  12,
