INSERT INTO chunks (id, skill_id, section_title, content, chunk_index, embedding) VALUES (
  '079c08d7-e04b-5a33-b8d0-80c490ee1acc',
  '2a590116-b715-573c-a481-c647d9b0488e',
  'Upgrade Checklist',
  '**Before starting**:
- [ ] Pre-upgrade health checks passed
- [ ] Binaries staged on all nodes
- [ ] preserve_downgrade_option set
- [ ] Recent backup exists
- [ ] Tested in staging
- [ ] Rollback procedure documented
- [ ] Team informed of upgrade window

**For each node**:
- [ ] Drain node
- [ ] Stop process
- [ ] Replace binary
- [ ] Start process
- [ ] Verify rejoined cluster
- [ ] Check no under-replicated ranges
- [ ] Wait 5-10 minutes
- [ ] Proceed to next node

**After all nodes upgraded**:
- [ ] All nodes show new version
- [ ] No under-replicated ranges
- [ ] No unavailable ranges
- [ ] Application tests passing
- [ ] Monitor for 24-48 hours
- [ ] Finalize version (after confidence established)',
  13,
