INSERT INTO chunks (id, skill_id, section_title, content, chunk_index, embedding) VALUES (
  '99bd6bec-d5eb-5a9e-93f5-796995e421d2',
  '2a590116-b715-573c-a481-c647d9b0488e',
  'Key Takeaways',
  '1. **preserve_downgrade_option enables rollback** - set before upgrading
2. **Drain before stop** - graceful connection handling
3. **One node at a time** - maintain quorum
4. **Verify health between nodes** - don''t rush
5. **Wait before finalizing** - test thoroughly first
6. **Keep old binary** - enables quick rollback
