INSERT INTO chunks (id, skill_id, section_title, content, chunk_index, embedding) VALUES (
  '59ef466b-48d3-5328-aeaf-5ca4b9deb17b',
  'e9cac7bf-e348-5101-9f82-c6970c0fe034',
  'Complete PITR Workflow',
  '### Step 1: Identify the Problem

```sql
-- Discover when bad data appeared
SELECT created_at, COUNT(*)
FROM orders
WHERE status = ''CORRUPTED''
GROUP BY created_at
ORDER BY created_at;

-- Result: Corruption started at 2026-03-05 14:32:18
```

**Target**: Restore to just before corruption (14:32:00)

### Step 2: Verify PITR Capability

```sql
-- Check backup has revision_history
SELECT * FROM [SHOW BACKUP FROM LATEST IN ''nodelocal://1/backups/prod'']
WHERE backup_type = ''full'';

-- Look for: has_revision_history = true
```

**If false**: Cannot do PITR, only restore to backup timestamps

### Step 3: Check GC TTL Window

```sql
-- How far back can we restore?
SHOW CLUSTER SETTING kv.gc.ttl;

-- Result: 4h0m0s means 4 hour PITR window
```

**Calculate**:
```
Current time: 15:00
GC TTL: 4 hours
PITR window: 11:00 → 15:00
Target time: 14:32
Status: ✅ Within window
```

### Step 4: Restore to Recovery Database

```sql
-- Restore to just before corruption
RESTORE DATABASE production
  FROM LATEST IN ''gs://backups/prod''
  AS OF SYSTEM TIME ''2026-03-05 14:31:50''
  WITH new_db_name = ''production_recovered'';
```

**Why new_db_name**:
- Preserves original database
- Allows data comparison
- Safer than immediate replacement

### Step 5: Validate Recovered Data

```sql
-- Verify recovered data is clean
SELECT COUNT(*) FROM production_recovered.orders
WHERE status = ''CORRUPTED'';
-- Result: 0 (good!)

-- Compare row counts
SELECT
  (SELECT COUNT(*) FROM production.orders) AS current_count,
  (SELECT COUNT(*) FROM production_recovered.orders) AS recovered_count;
```

### Step 6: Merge or Replace

**Option A: Replace entire database**
```sql
-- Drop corrupted database
DROP DATABASE production CASCADE;

-- Rename recovered to production
ALTER DATABASE production_recovered RENAME TO production;
```

**Option B: Selective data merge**
```sql
-- Copy only affected records
DELETE FROM production.orders WHERE status = ''CORRUPTED'';

INSERT INTO production.orders
SELECT * FROM production_recovered.orders
WHERE created_at >= ''2026-03-05 14:00:00'';
```',
