INSERT INTO chunks (id, skill_id, section_title, content, chunk_index, embedding) VALUES (
  '31f1b34a-244e-5fe1-b430-05891f981a81',
  'e9cac7bf-e348-5101-9f82-c6970c0fe034',
  'Common Patterns',
  '### Pattern 1: Recover Last Good State

```sql
-- Restore to multiple points to find last good state
RESTORE DATABASE mydb FROM LATEST IN ''nodelocal://1/backups''
  AS OF SYSTEM TIME ''-30m'' WITH new_db_name = ''mydb_30m_ago'';

RESTORE DATABASE mydb FROM LATEST IN ''nodelocal://1/backups''
  AS OF SYSTEM TIME ''-1h'' WITH new_db_name = ''mydb_1h_ago'';

-- Query each to find when data was still clean
```

### Pattern 2: Table-Level PITR

```sql
-- Restore single table to point in time
RESTORE TABLE mydb.orders
  FROM LATEST IN ''nodelocal://1/backups''
  AS OF SYSTEM TIME ''-1h''
  WITH into_db = ''mydb_recovered'';
```',
