INSERT INTO chunks (id, skill_id, section_title, content, chunk_index, embedding) VALUES (
  'c8159359-1fe5-5f0e-8c8f-4d6f2d2da409',
  'e9cac7bf-e348-5101-9f82-c6970c0fe034',
  'Troubleshooting',
  '### Issue 1: "AS OF SYSTEM TIME before GC threshold"

**Error**:
```
ERROR: AS OF SYSTEM TIME: timestamp before GC threshold
```

**Cause**: Trying to restore beyond GC TTL window

**Solution**:
```sql
-- Check GC TTL
SHOW CLUSTER SETTING kv.gc.ttl;

-- Can only restore within GC TTL window
-- For future: extend GC TTL before incident
```

### Issue 2: "backup does not contain revision history"

**Error**:
```
ERROR: backup does not contain revision history
```

**Cause**: Backup created without `WITH revision_history`

**Solution**:
```sql
-- Future backups must use revision_history
BACKUP INTO ''nodelocal://1/backups/new''
  WITH revision_history;

-- For now: only restore to backup timestamps
SHOW BACKUPS IN ''nodelocal://1/backups'';
```',
