INSERT INTO chunks (id, skill_id, section_title, content, chunk_index, embedding) VALUES (
  '00e2297d-a28d-5f13-a185-96fefd70cf84',
  'e9cac7bf-e348-5101-9f82-c6970c0fe034',
  'Best Practices',
  '1. **Always use WITH revision_history** for production backups
2. **Set appropriate GC TTL** for your recovery requirements
3. **Restore to new database first** to validate before replacing
4. **Document incident timeline** to choose correct recovery point
5. **Test PITR regularly** during backup testing
