INSERT INTO chunks (id, skill_id, section_title, content, chunk_index, embedding) VALUES (
  '8f4fa381-43ec-55fc-896a-1efff99b918f',
  '68d4e21c-7c04-59ad-b8a0-bec37d9d0149',
  'Basic Syntax',
  '```sql
-- Daily incremental backups, weekly full backups
CREATE SCHEDULE daily_backup
  FOR BACKUP INTO ''nodelocal://1/backups/scheduled''
  RECURRING ''@daily''
  FULL BACKUP ''@weekly'';
```

**Returns**: Schedule ID for management',
  2,
