  RECURRING ''@daily''
  FULL BACKUP ''@weekly'';
```

### GCS

```sql
CREATE SCHEDULE gcs_backup
  FOR BACKUP INTO ''gs://my-bucket/backups?AUTH=specified&CREDENTIALS=xxx''
  RECURRING ''@daily''
  FULL BACKUP ''@weekly'';
```',
