INSERT INTO chunks (id, skill_id, section_title, content, chunk_index, embedding) VALUES (
  '13bc3d85-dfe7-58af-8fc2-e50b2e28e838',
  '68d4e21c-7c04-59ad-b8a0-bec37d9d0149',
  'Schedule Lifecycle',
  '**Create** → **Monitor** → **Modify/Pause** → **Drop**

```sql
-- Create
CREATE SCHEDULE ...

-- Monitor  
SHOW SCHEDULES;

-- Pause for maintenance
PAUSE SCHEDULES <id>;

-- Resume
RESUME SCHEDULES <id>;

-- Remove permanently
DROP SCHEDULES <id>;
