INSERT INTO chunks (id, skill_id, section_title, content, chunk_index, embedding) VALUES (
  'c7810df2-c227-534f-b5d5-85ca5cb843fd',
  'd2775990-b0c8-5802-b36c-6d4adf8dabc5',
  'Basic Syntax',
  '```sql
-- Restore database from latest backup
RESTORE DATABASE mydb FROM LATEST IN ''nodelocal://1/backups/mydb'';

-- Restore to different name (for testing/comparison)
RESTORE DATABASE mydb FROM LATEST IN ''nodelocal://1/backups/mydb''
  WITH new_db_name = ''mydb_restored'';
```',
