INSERT INTO chunks (id, skill_id, section_title, content, chunk_index, embedding) VALUES (
  '944667dd-23fb-5fc0-bd1d-40f82292ca18',
  'd2775990-b0c8-5802-b36c-6d4adf8dabc5',
  'What Gets Restored',
  '### Included in Database Restore

- All tables and data rows
- Primary and secondary indexes
- Table schemas and constraints
- Sequences
- Views
- User-defined types
- Table-level zone configurations

### NOT Included

- Users and roles (use cluster restore)
- Permissions on database (must re-grant)
- Other databases
