INSERT INTO chunks (id, skill_id, section_title, content, chunk_index, embedding) VALUES (
  '93666ae7-e807-5e63-8805-70601f4c7a45',
  '6c2517c5-79e9-52c3-943c-4b08f820eac9',
  'Common Scenarios',
  '### Scenario 1: 3-Region Setup (US-focused)

**Use case**: Application primarily serves US users with some European traffic

```sql
CREATE DATABASE app_db
  PRIMARY REGION ''us-east''
  REGIONS ''us-east'', ''us-west'', ''eu-west''
  SURVIVE ZONE FAILURE;
```

**Characteristics:**
- Primary region: `us-east` (most users)
- 5 replicas across 3 regions
- Zone-level fault tolerance
- Lower write latency for US users

### Scenario 2: 5-Region Global Setup

**Use case**: Global application requiring high availability

```sql
CREATE DATABASE global_app
  PRIMARY REGION ''us-east''
  REGIONS ''us-east'', ''us-west'', ''eu-west'', ''ap-south'', ''ap-southeast''
  SURVIVE REGION FAILURE;
```

**Characteristics:**
- 5 replicas distributed globally
- Survives entire region failure
- Higher write latency (cross-region commits)
- Best for mission-critical applications

### Scenario 3: Single Region to Start

**Use case**: Start simple, expand later

```sql
CREATE DATABASE startup_db
  PRIMARY REGION ''us-east'';
```

**Expand later:**
```sql
ALTER DATABASE startup_db ADD REGION ''us-west'';
ALTER DATABASE startup_db ADD REGION ''eu-west'';
ALTER DATABASE startup_db SURVIVE REGION FAILURE;
```

### Scenario 4: Regional Compliance (EU Data Residency)

**Use case**: EU data must stay in EU regions

```sql
CREATE DATABASE eu_app
  PRIMARY REGION ''eu-west''
  REGIONS ''eu-west'', ''eu-central'', ''eu-north''
  SURVIVE REGION FAILURE;
```

Later configure super regions for strict data domiciling:
```sql
ALTER DATABASE eu_app
  ADD SUPER REGION ''eu''
  VALUES ''eu-west'', ''eu-central'', ''eu-north'';
```',
