INSERT INTO chunks (id, skill_id, section_title, content, chunk_index, embedding) VALUES (
  '8b2350bf-48a9-553a-9487-be11330af610',
  '6c2517c5-79e9-52c3-943c-4b08f820eac9',
  'Next Steps',
  'After creating a multi-region database:

1. **Create tables with appropriate locality**:
   - `REGIONAL BY TABLE` for region-specific data
   - `REGIONAL BY ROW` for user-partitioned data
   - `GLOBAL` for reference data

2. **Configure table-specific settings**:
   - Set table localities based on access patterns
   - Add secondary indexes for cross-region queries

3. **Monitor performance**:
   - Check query latency across regions
   - Verify replica distribution with `SHOW RANGES`

4. **Implement application logic**:
   - Use follower reads for stale data tolerance
   - Route writes to appropriate regions',
  10,
