INSERT INTO chunks (id, skill_id, section_title, content, chunk_index, embedding) VALUES (
  '9af2fb10-8b78-5247-bac2-f4e951ebbf88',
  'aa3e42eb-ecca-52ae-a888-e42fcd94ab39',
  'What This Skill Teaches',
  'This skill teaches you how to configure CockroachDB databases to survive complete regional failures using the `ALTER DATABASE ... SURVIVE REGION FAILURE` statement. You''ll learn the replica topology, quorum mathematics, latency trade-offs, and when region-level survival is appropriate for your application''s resilience requirements.

**Key Learning Outcomes:**

- Configure databases for region-level survival goals
- Understand the 5-replica, 3-voter topology across regions
- Calculate quorum requirements and fault tolerance
- Evaluate trade-offs between region and zone survival
- Verify survival goal configuration and replica placement
- Recognize mission-critical use cases requiring region survival',
  1,
