INSERT INTO chunks (id, skill_id, section_title, content, chunk_index, embedding) VALUES (
  'dc4a174e-e3eb-51d7-a47b-bd926db79f73',
  'aa3e42eb-ecca-52ae-a888-e42fcd94ab39',
  'Why Region Survival Matters',
  'By default, CockroachDB databases use ZONE survival, which tolerates individual availability zone failures but cannot survive an entire region becoming unavailable. For mission-critical applications that require continuous operation despite catastrophic regional failures (natural disasters, power grid failures, cloud provider regional outages), region-level survival ensures your database remains fully available for both reads and writes.

**The Guarantee**: With region survival configured, your database remains fully operational even if an entire cloud region goes offline.

**The Cost**: Write latency increases by at least the network round-trip time to the nearest region (typically 50-150ms depending on geography).',
