INSERT INTO chunks (id, skill_id, section_title, content, chunk_index, embedding) VALUES (
  '713e62ca-b1e9-5401-ac58-ffab35c84571',
  'aa3e42eb-ecca-52ae-a888-e42fcd94ab39',
  'Prerequisites',
  'Before configuring region survival, ensure your cluster meets these requirements:

1. **Minimum Three Regions**: At least 3 database regions must be configured
   - Two regions are insufficient (cannot maintain quorum if one fails)
   - More regions provide additional redundancy

2. **Multi-Region Database**: Database must have a PRIMARY REGION set
   - Use `ALTER DATABASE ... SET PRIMARY REGION` first
   - Then add additional regions with `ADD REGION`

3. **Cluster Topology**: Cluster nodes must span at least 3 geographic regions
   - Check available cluster regions: `SHOW REGIONS FROM CLUSTER`

4. **Sufficient Resources**: Each region needs capacity for additional replicas
   - Region survival uses 5 replicas vs. 3 for zone survival
   - Increased storage and replication overhead',
  3,
