INSERT INTO chunks (id, skill_id, section_title, content, chunk_index, embedding) VALUES (
  '973c4957-07b3-5d1d-a442-761857673d0f',
  'aa3e42eb-ecca-52ae-a888-e42fcd94ab39',
  'Additional Resources',
  '### Official CockroachDB Documentation

- [Multi-Region Survival Goals](https://www.cockroachlabs.com/docs/stable/multiregion-survival-goals) - Complete reference for survival goal configuration
- [ALTER DATABASE](https://www.cockroachlabs.com/docs/stable/alter-database) - SQL syntax reference for survival goal statements
- [When to Use ZONE vs. REGION Survival Goals](https://www.cockroachlabs.com/docs/stable/when-to-use-zone-vs-region-survival-goals.html) - Decision guide for choosing survival goals
- [How to Choose a Multi-Region Configuration](https://www.cockroachlabs.com/docs/stable/choosing-a-multi-region-configuration) - Comprehensive multi-region planning guide
