INSERT INTO chunks (id, skill_id, section_title, content, chunk_index, embedding) VALUES (
  '6962f042-d638-5c59-8e01-324beebc0451',
  '68e4834a-0470-5b30-b9d4-e0ab840a89a1',
  'Prerequisites',
  '### 1. Verify Multi-Region Database Setup

```sql
-- Check database has regions configured
SHOW REGIONS FROM DATABASE mydb;

-- Expected output:
--   database |  region   | primary |  zones
-- -----------+-----------+---------+----------
--   mydb     | us-east   | true    | {us-east-1a,us-east-1b,us-east-1c}
--   mydb     | us-west   | false   | {us-west-1a,us-west-1b,us-west-1c}
--   mydb     | eu-west   | false   | {eu-west-1a,eu-west-1b,eu-west-1c}
```

### 2. Identify Current Table Locality

```sql
-- Check current locality setting
SHOW CREATE TABLE mydb.orders;

-- Look for LOCALITY clause in output:
-- CREATE TABLE orders (...) LOCALITY REGIONAL BY TABLE IN PRIMARY REGION
```',
