INSERT INTO chunks (id, skill_id, section_title, content, chunk_index, embedding) VALUES (
  'fdf78da4-56df-594b-b60d-6a0ccd57c03b',
  '68e4834a-0470-5b30-b9d4-e0ab840a89a1',
  'Verification and Validation',
  '### Check Replica Distribution

```sql
-- Detailed replica placement for a table
WITH replica_info AS (
  SHOW RANGES FROM TABLE us_orders WITH DETAILS
)
SELECT
  start_key,
  end_key,
  replicas,
  replica_localities,
  lease_holder,
  lease_holder_locality
FROM replica_info
LIMIT 10;

-- Expected: All replicas and leaseholders in us-east region
```

### Monitor Data Movement Progress

```sql
-- Check for under-replicated ranges during migration
SET allow_unsafe_internals = true;
SELECT
  table_name,
  count(*) as under_replicated_ranges
FROM crdb_internal.ranges
WHERE array_length(replicas, 1) < 3
  AND table_name = ''us_orders''
GROUP BY table_name;

-- Should show 0 when migration complete
```

### Verify Zone Configuration

```sql
-- Inspect zone configuration applied to table
SHOW ZONE CONFIGURATION FROM TABLE us_orders;

-- Expected output shows constraints for target region:
-- ALTER TABLE mydb.public.us_orders CONFIGURE ZONE USING
--   constraints = ''[+region=us-east]'',
--   lease_preferences = ''[[+region=us-east]]'';
```',
