INSERT INTO chunks (id, skill_id, section_title, content, chunk_index, embedding) VALUES (
  '7aa808a9-0896-53d6-ba4a-b6f71730ac2c',
  '68e4834a-0470-5b30-b9d4-e0ab840a89a1',
  'Common Errors and Troubleshooting',
  '### Error 1: Region Does Not Exist

```sql
ALTER TABLE orders SET LOCALITY REGIONAL BY TABLE IN ''asia-east'';
-- ERROR: region "asia-east" does not exist
-- HINT: valid regions: us-east, us-west, eu-west
```

**Solution:**

```sql
-- Add region to database first
ALTER DATABASE mydb ADD REGION ''asia-east'';

-- Then configure table locality
ALTER TABLE orders SET LOCALITY REGIONAL BY TABLE IN ''asia-east'';
```

### Error 2: Table Already Uses REGIONAL BY ROW

```sql
ALTER TABLE users SET LOCALITY REGIONAL BY TABLE IN ''us-east'';
-- ERROR: cannot change REGIONAL BY ROW table to REGIONAL BY TABLE
-- HINT: use DROP COLUMN crdb_region first
```

**Solution:**

```sql
-- Remove crdb_region column (destructive - loses row-level region data)
ALTER TABLE users DROP COLUMN crdb_region;

-- Now change to REGIONAL BY TABLE
ALTER TABLE users SET LOCALITY REGIONAL BY TABLE IN ''us-east'';
```

### Error 3: Cannot Drop Region With Tables

```sql
ALTER DATABASE mydb DROP REGION ''eu-west'';
-- ERROR: cannot drop region "eu-west": table "eu_customers" is homed in this region
```

**Solution:**

```sql
-- Option 1: Move table to different region
ALTER TABLE eu_customers SET LOCALITY REGIONAL BY TABLE IN ''us-east'';

-- Option 2: Change to REGIONAL BY ROW (allows multi-region)
ALTER TABLE eu_customers SET LOCALITY REGIONAL BY ROW;

-- Option 3: Drop table (if no longer needed)
DROP TABLE eu_customers;

-- Then drop region
ALTER DATABASE mydb DROP REGION ''eu-west'';
```

### Error 4: Slow Cross-Region Queries

**Symptom**: Queries from eu-west to us-east table are slow.

```sql
-- From eu-west node: 100-200ms due to cross-region leaseholder access
SELECT * FROM us_orders WHERE customer_id = ''abc123'';
```

**Solutions:**

```sql
-- Option 1: Use follower reads for stale data (5-10ms latency)
SELECT * FROM us_orders AS OF SYSTEM TIME follower_read_timestamp()
WHERE customer_id = ''abc123'';

-- Option 2: Change to REGIONAL BY ROW if multi-region access needed
ALTER TABLE us_orders SET LOCALITY REGIONAL BY ROW;

-- Option 3: Denormalize data with regional copies
CREATE TABLE eu_order_cache AS SELECT * FROM us_orders WHERE region = ''EU'';
ALTER TABLE eu_order_cache SET LOCALITY REGIONAL BY TABLE IN ''eu-west'';
```',
