INSERT INTO chunks (id, skill_id, section_title, content, chunk_index, embedding) VALUES (
  '9a8e4fe9-91b4-564a-b4ac-4c43ba745d9f',
  '68e4834a-0470-5b30-b9d4-e0ab840a89a1',
  'Best Practices',
  '**1. Plan Before Configuring**
- Audit current localities using `information_schema.tables`
- Analyze access patterns to identify region affinity
- Consider future growth and region changes

**2. Configure During Low-Traffic Windows**
- Data movement consumes cluster resources
- Schedule during maintenance windows for large tables
- Monitor cluster metrics during migration

**3. Verify After Configuration**
```sql
-- Verify all leases in target region
WITH table_ranges AS (SHOW RANGES FROM TABLE critical_table WITH DETAILS)
SELECT
  count(*) as total_ranges,
  count(DISTINCT substring(lease_holder_locality FROM ''region=([^,]+)'')) as regions
FROM table_ranges;
-- Expected: regions = 1 for REGIONAL BY TABLE
```

**4. Document Locality Decisions**
```sql
COMMENT ON TABLE eu_customers IS
  ''REGIONAL BY TABLE IN eu-west - GDPR compliance requires EU data residency'';
```',
  10,
