INSERT INTO chunks (id, skill_id, section_title, content, chunk_index, embedding) VALUES (
  '42c16146-a25a-5143-807b-a375a305d89e',
  '3f16635c-d7f4-5490-865d-c41aef7aee1e',
  'Verification Examples',
  '### Example 1: Verify Replica Placement

```sql
-- Check replica distribution across regions
WITH replica_details AS (
  SELECT
    range_id,
    UNNEST(replicas) AS store_id
  FROM
    crdb_internal.ranges
  WHERE
    table_name = ''countries''
)
SELECT
  s.store_id,
  s.node_id,
  n.locality,
  COUNT(*) AS num_ranges
FROM
  replica_details rd
  JOIN crdb_internal.kv_store_status s ON rd.store_id = s.store_id
  JOIN crdb_internal.kv_node_status n ON s.node_id = n.node_id
GROUP BY
  s.store_id, s.node_id, n.locality
ORDER BY
  n.locality;
```

Expected: Each region has replicas for all ranges.',
