INSERT INTO chunks (id, skill_id, section_title, content, chunk_index, embedding) VALUES (
  '4539de96-fbd0-5c87-9d63-6b4947de418a',
  '3f16635c-d7f4-5490-865d-c41aef7aee1e',
  'When to Convert Back to REGIONAL BY TABLE',
  'Convert away from GLOBAL if:

1. **Write rate increases** above 10% of operations
2. **Storage costs** become prohibitive (replicas in all regions)
3. **Access pattern** changes to single-region dominant (>90% queries)

```sql
-- Convert back to REGIONAL BY TABLE
ALTER TABLE countries SET LOCALITY REGIONAL BY TABLE IN ''us-east1'';
