INSERT INTO chunks (id, skill_id, section_title, content, chunk_index, embedding) VALUES (
  '08bdb1cd-0029-5a02-ad75-7936a4f98654',
  '28b0c72a-66db-5949-b183-d2052b669bbf',
  'Verification and Inspection',
  '### Check Voting vs Non-Voting Replicas

```sql
-- View replica details including voting status
SELECT
  range_id,
  replicas,
  voting_replicas,
  non_voting_replicas
FROM
  crdb_internal.ranges
WHERE
  table_name = ''countries'';
```

### Identify Non-Voting Replica Lag

```sql
-- Check replication lag for non-voting replicas
SELECT
  range_id,
  store_id,
  replica_id,
  CASE WHEN is_voter THEN ''VOTING'' ELSE ''NON-VOTING'' END AS type,
  behind_nanos / 1000000 AS lag_ms
FROM
  crdb_internal.kv_replica_status
WHERE
  table_name = ''countries''
ORDER BY
  range_id, store_id;
```',
