INSERT INTO chunks (id, skill_id, section_title, content, chunk_index, embedding) VALUES (
  '4ea8f459-f700-5961-8f17-560f8f30ff12',
  '28b0c72a-66db-5949-b183-d2052b669bbf',
  'Common Misconceptions',
  '**Misconception 1**: "Non-voting replicas are unsafe"
- ❌ False: They receive the same data, just asynchronously
- ✅ Truth: Writes are durable once committed to voting replicas

**Misconception 2**: "Non-voting replicas hurt availability"
- ❌ False: They don''t participate in quorum, so their failures don''t matter
- ✅ Truth: They improve read availability in additional regions

**Misconception 3**: "More replicas always improve durability"
- ❌ False: Only voting replicas contribute to write durability
- ✅ Truth: 3 voting + 2 non-voting = same durability as 3 voting alone

**Misconception 4**: "Non-voting replicas can be leaseholders"
- ❌ False: Only voting replicas can hold leases
- ✅ Truth: Non-voting replicas are read-only followers',
