INSERT INTO chunks (id, skill_id, section_title, content, chunk_index, embedding) VALUES (
  '5f07d3dc-1f65-56ae-b2d6-6b9a68330284',
  '573611cb-3b5b-5477-be3c-b9346b02bc53',
  'Prerequisites Before Adding Regions',
  '### 1. Verify Cluster Has Nodes in Target Region

```sql
-- Check what regions are available in cluster
SHOW REGIONS FROM CLUSTER;
```

**Expected output:**
```
  region   | zones
-----------+--------
  us-east  | {us-east-1}
  us-west  | {us-west-1}
  eu-west  | {eu-west-1}
```

The region you want to add MUST appear in this list.

### 2. Verify Node Distribution and Health

```sql
-- Verify nodes in target region (need 3+ for production)
SELECT node_id, locality
FROM crdb_internal.gossip_nodes
WHERE locality LIKE ''%region=eu-west%'';

-- Check cluster health (must be 0)
SET allow_unsafe_internals = true;
SELECT count(*) as under_replicated_ranges
FROM crdb_internal.ranges
WHERE array_length(replicas, 1) < 3;
```',
  3,
