INSERT INTO chunks (id, skill_id, section_title, content, chunk_index, embedding) VALUES (
  '55437345-9967-583f-9be8-3dfa11a5331e',
  '573611cb-3b5b-5477-be3c-b9346b02bc53',
  'Monitoring Rebalancing',
  '### Monitor Progress

```sql
-- Watch range distribution
SELECT
  substring(lease_holder_locality, ''region=([^,]+)'') as region,
  count(*) as ranges
FROM crdb_internal.ranges
WHERE database_name = ''mydb''
GROUP BY region;

-- Check under-replicated ranges (should be 0)
SET allow_unsafe_internals = true;
SELECT count(*) FROM crdb_internal.ranges
WHERE array_length(replicas, 1) < 3;
```

**Rebalancing timeline:**
- Small (<10 GB): 5-15 minutes
- Medium (10-100 GB): 15-60 minutes
- Large (>100 GB): 1-6 hours',
