INSERT INTO chunks (id, skill_id, section_title, content, chunk_index, embedding) VALUES (
  '0aeb38fb-91de-596a-8bd2-9cc34fe150ac',
  '573611cb-3b5b-5477-be3c-b9346b02bc53',
  'Performance Impact',
  '**During addition:**
- Minimal impact on reads (leaseholders unchanged)
- Slight write latency increase (more replicas)
- Increased network traffic (data copying)
- Higher CPU/disk usage during rebalancing

**After addition:**
- Lower latency for users in new region
- Better disaster recovery coverage
- Higher write latency (more replicas to update)
- Increased storage and bandwidth costs',
  9,
