INSERT INTO chunks (id, skill_id, section_title, content, chunk_index, embedding) VALUES (
  '4e3e6e60-24b2-5716-8fab-71b9f094a592',
  '573611cb-3b5b-5477-be3c-b9346b02bc53',
  'Common Scenarios',
  '### Scenario 1: Expanding to European Market

```sql
-- Current: US-only database
SHOW REGIONS FROM DATABASE ecommerce;
--   ecommerce | us-east | true  | {us-east-1}
--   ecommerce | us-west | false | {us-west-1}

-- Add EU region for European customers
ALTER DATABASE ecommerce ADD REGION ''eu-west'';

-- Verify addition
SHOW REGIONS FROM DATABASE ecommerce;

-- Configure EU-specific table
CREATE TABLE eu_orders (
  id UUID PRIMARY KEY,
  customer_id UUID,
  created_at TIMESTAMP DEFAULT now()
) LOCALITY REGIONAL BY TABLE IN ''eu-west'';
```

### Scenario 2: Region Addition for REGIONAL BY ROW Database

```sql
-- Current: User data partitioned by region
SHOW CREATE TABLE users;
-- ... LOCALITY REGIONAL BY ROW

-- Add new region
ALTER DATABASE userdb ADD REGION ''sa-east'';

-- Migrate South American users'' data
UPDATE users
SET crdb_region = ''sa-east''
WHERE country IN (''BR'', ''AR'', ''CL'', ''CO'');

-- Verify data distribution
SELECT crdb_region, count(*) as user_count
FROM users
GROUP BY crdb_region;
```',
