INSERT INTO chunks (id, skill_id, section_title, content, chunk_index, embedding) VALUES (
  '287ece3c-8bf4-53c0-8de5-637496eb9c8d',
  '573611cb-3b5b-5477-be3c-b9346b02bc53',
  'Summary',
  'Adding regions to multi-region databases expands geographic reach with automatic rebalancing:

✅ Syntax: `ALTER DATABASE <db> ADD REGION ''<region>''`
✅ Prerequisite: Cluster must have nodes in target region
✅ Automatic: Replica rebalancing happens in background
✅ Verification: Use `SHOW REGIONS FROM DATABASE`
✅ Impact: Tables receive replicas based on locality and survival goal
✅ Performance: Add during low-traffic windows, monitor rebalancing
✅ Safety: Add one region at a time, verify health between additions

**Golden Rule:** Always verify the cluster has nodes in the region before attempting to add it to a database.',
