INSERT INTO chunks (id, skill_id, section_title, content, chunk_index, embedding) VALUES (
  '3f77147c-9a75-5905-b51e-a60c9bb6a69f',
  'bd7371a8-3a83-5d2f-8ff6-3fb0f43832e0',
  'What This Skill Teaches',
  'Learn to systematically optimize multi-region CockroachDB deployments for minimal latency through:

- Analyzing access patterns to choose optimal table localities
- Selecting primary region based on traffic distribution
- Configuring leaseholder placement for read optimization
- Implementing follower reads for stale-tolerant workloads
- Tuning zone configurations for performance
- Applying application-level optimizations
- Monitoring and iterating on latency improvements

This comprehensive skill covers the full optimization lifecycle from design through operations.',
