INSERT INTO chunks (id, skill_id, section_title, content, chunk_index, embedding) VALUES (
  '0b50495c-45da-53c6-a68a-e2b80e067246',
  'bd7371a8-3a83-5d2f-8ff6-3fb0f43832e0',
  'Overview',
  'Multi-region latency optimization requires a layered approach across schema design, cluster topology, and application patterns.

**Latency sources:**
- Network latency: 70-150ms cross-region (unavoidable, design around it)
- Consensus latency: 1-2 network round trips (minimize with locality-aware design)
- Query planning overhead: 1-5ms (reduce by co-locating related data)

**Optimization layers (impact order):**
1. Schema layer: Table locality selection, primary key design, index locality
2. Topology layer: Primary region placement, leaseholder preferences, zone configs
3. Application layer: Connection pooling, query patterns, follower reads, caching

**Latency targets:**
- Same-region reads: 5-15ms (local leaseholder)
- Cross-region reads: 75-150ms (network + query)
- Follower reads: 5-15ms (local replica, stale)
- Same-region writes: 10-25ms (local consensus)
- Cross-region writes: 80-200ms (network + consensus)',
  2,
