INSERT INTO chunks (id, skill_id, section_title, content, chunk_index, embedding) VALUES (
  '5f05a381-5e3c-50d6-a2c3-74425c87b21f',
  '53189b9e-d3a9-553b-95cb-cdf9a9eb9d62',
  'Overview',
  'Follower reads enable CockroachDB to serve read queries from the nearest replica instead of always routing to the leaseholder. This dramatically reduces read latency in multi-region deployments by avoiding cross-region network hops, at the cost of slight data staleness (typically ~4.8 seconds).

**Key Concept**: By reading historical data using `AS OF SYSTEM TIME`, CockroachDB can serve reads from any replica (including local non-voting replicas), not just the leaseholder.

**Trade-off**: Lower latency for eventual consistency. Perfect for analytics, dashboards, and reporting where real-time accuracy is not critical.',
  1,
