INSERT INTO chunks (id, skill_id, section_title, content, chunk_index, embedding) VALUES (
  '59683fa2-a31e-57eb-a263-e88eb86924aa',
  '53189b9e-d3a9-553b-95cb-cdf9a9eb9d62',
  'Complete Working Examples',
  '### Example 1: Analytics Dashboard (Basic Follower Read)

```sql
-- Scenario: Real-time sales dashboard showing today''s orders
-- Requirement: Low latency, can tolerate 5-second staleness

-- Create test table
CREATE TABLE orders (
  id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  customer_id UUID,
  product_id UUID,
  amount DECIMAL(10,2),
  status STRING,
  created_at TIMESTAMP DEFAULT now(),
  region STRING
);

-- Insert sample data
INSERT INTO orders (customer_id, product_id, amount, status, region)
SELECT
  gen_random_uuid(),
  gen_random_uuid(),
  (random() * 1000)::DECIMAL(10,2),
  CASE (random() * 3)::INT
    WHEN 0 THEN ''pending''
    WHEN 1 THEN ''completed''
    ELSE ''cancelled''
  END,
  CASE (random() * 3)::INT
    WHEN 0 THEN ''us-east''
    WHEN 1 THEN ''us-west''
    ELSE ''eu-west''
  END
FROM generate_series(1, 10000);

-- Dashboard query WITHOUT follower reads (slow)
EXPLAIN ANALYZE
SELECT
  region,
  status,
  count(*) as order_count,
  sum(amount) as total_revenue
FROM orders
WHERE created_at > now() - ''24 hours''::INTERVAL
GROUP BY region, status;

-- Dashboard query WITH follower reads (fast)
EXPLAIN ANALYZE
SELECT
  region,
  status,
  count(*) as order_count,
  sum(amount) as total_revenue
FROM orders
AS OF SYSTEM TIME follower_read_timestamp()
WHERE created_at > now() - ''24 hours''::INTERVAL
GROUP BY region, status;
```

**Expected Results:**
- Without follower reads: 50-150ms (cross-region leaseholder read)
- With follower reads: 5-15ms (local replica read)
- Data staleness: ~4.8 seconds (acceptable for dashboard)

### Example 2: Reporting Query with Exact Staleness

```sql
-- Scenario: Hourly report showing sales by region
-- Requirement: Consistent snapshot across all tables

-- Get current follower timestamp for consistent multi-table read
SELECT follower_read_timestamp() AS report_timestamp \\gset

-- Run multiple queries against same timestamp
SELECT
  r.region,
  count(DISTINCT o.customer_id) as unique_customers,
  count(o.id) as total_orders,
  sum(o.amount) as revenue
FROM orders o
JOIN regions r ON o.region = r.code
AS OF SYSTEM TIME :''report_timestamp''
WHERE o.created_at > now() - ''1 hour''::INTERVAL
GROUP BY r.region;

-- Alternative: Use explicit staleness
SELECT
  region,
  count(*) as orders,
  avg(amount) as avg_order_value
FROM orders
AS OF SYSTEM TIME ''-5s''
WHERE created_at > now() - ''1 hour''::INTERVAL
GROUP BY region;
```

### Example 3: Product Catalog with Bounded Staleness

```sql
-- Scenario: E-commerce product search
-- Requirement: Results no more than 3 seconds stale

-- Create product catalog
CREATE TABLE product_catalog (
  id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  name STRING,
  category STRING,
  price DECIMAL(10,2),
  in_stock BOOL,
  updated_at TIMESTAMP DEFAULT now()
);

-- Insert products
INSERT INTO product_catalog (name, category, price, in_stock)
VALUES
  (''Laptop Pro 15'', ''electronics'', 1299.99, true),
  (''Wireless Mouse'', ''electronics'', 29.99, true),
  (''Office Chair'', ''furniture'', 349.99, true),
  (''Desk Lamp'', ''furniture'', 79.99, false);

-- Search with bounded staleness (max 3 seconds old)
SELECT id, name, category, price, in_stock
FROM product_catalog
AS OF SYSTEM TIME with_max_staleness(''3s'')
WHERE category = ''electronics''
  AND in_stock = true
ORDER BY price DESC;

-- Alternative with explicit bound
SELECT id, name, price
FROM product_catalog
AS OF SYSTEM TIME with_min_timestamp(now() - ''3s''::INTERVAL)
WHERE category = ''furniture''
ORDER BY name;
```

