INSERT INTO chunks (id, skill_id, section_title, content, chunk_index, embedding) VALUES (
  '18c5b6b9-2849-5b1b-9f2b-5ad16bfb7fa5',
  '53189b9e-d3a9-553b-95cb-cdf9a9eb9d62',
  'Common Patterns and Use Cases',
  '### Pattern 1: Read-Heavy Dashboards

```sql
-- Application: Real-time monitoring dashboard
-- Staleness: 5 seconds acceptable

-- CPU usage by node
SELECT
  node_id,
  avg(cpu_percent) as avg_cpu,
  max(cpu_percent) as max_cpu
FROM metrics
AS OF SYSTEM TIME follower_read_timestamp()
WHERE timestamp > now() - ''5 minutes''::INTERVAL
GROUP BY node_id;

-- Request rate by endpoint
SELECT
  endpoint,
  count(*) as request_count,
  avg(latency_ms) as avg_latency
FROM http_logs
AS OF SYSTEM TIME follower_read_timestamp()
WHERE timestamp > now() - ''1 hour''::INTERVAL
GROUP BY endpoint
ORDER BY request_count DESC
LIMIT 10;
```

### Pattern 2: Reporting and Analytics

```sql
-- Application: Daily sales report
-- Staleness: Several seconds acceptable for aggregates

-- Daily revenue by region
SELECT
  date_trunc(''day'', created_at) as report_date,
  region,
  count(*) as orders,
  sum(amount) as revenue
FROM orders
AS OF SYSTEM TIME follower_read_timestamp()
WHERE created_at > now() - ''30 days''::INTERVAL
GROUP BY report_date, region
ORDER BY report_date DESC, revenue DESC;
```

### Pattern 3: Search and Browse Functionality

```sql
-- Application: Product search/browse
-- Staleness: 3-5 seconds acceptable

-- Product search with filters
SELECT id, name, category, price, rating
FROM products
AS OF SYSTEM TIME with_max_staleness(''5s'')
WHERE category = ''electronics''
  AND price BETWEEN 100 AND 500
  AND in_stock = true
ORDER BY rating DESC, price ASC
LIMIT 20;
```

### Pattern 4: Consistent Multi-Query Reads

```sql
-- Application: Multi-step wizard or workflow
-- Requirement: Consistent snapshot across queries

-- Store timestamp for session consistency
BEGIN;
SET LOCAL as_of_system_time = follower_read_timestamp();

-- Multiple queries see same snapshot
SELECT * FROM users WHERE id = ''user-123'';
SELECT * FROM orders WHERE user_id = ''user-123'';
SELECT * FROM addresses WHERE user_id = ''user-123'';

COMMIT;
```',
