INSERT INTO chunks (id, skill_id, section_title, content, chunk_index, embedding) VALUES (
  '2c766458-8c75-5347-89c9-cbc6d54828a8',
  '53189b9e-d3a9-553b-95cb-cdf9a9eb9d62',
  'Performance Measurement',
  '### Measuring Latency Reduction

```sql
-- Create test function to measure query timing
CREATE TABLE latency_test (
  id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  data STRING,
  region STRING
);

INSERT INTO latency_test (data, region)
SELECT
  repeat(''x'', 100),
  CASE (random() * 3)::INT WHEN 0 THEN ''us-east'' WHEN 1 THEN ''us-west'' ELSE ''eu-west'' END
FROM generate_series(1, 100000);

-- Test 1: Standard read (baseline)
\\timing on
SELECT count(*), region FROM latency_test GROUP BY region;
\\timing off
-- Time: 145ms

-- Test 2: Follower read
\\timing on
SELECT count(*), region
FROM latency_test
AS OF SYSTEM TIME follower_read_timestamp()
GROUP BY region;
\\timing off
-- Time: 12ms

-- Improvement: ~12x faster
```

### Monitoring Follower Read Usage

```sql
-- Check if queries are using follower reads
SELECT
  fingerprint,
  query,
  count,
  mean_exec_time,
  mean_rows_read
FROM crdb_internal.statement_statistics
WHERE query LIKE ''%follower_read_timestamp%''
ORDER BY count DESC
LIMIT 10;
```',
