INSERT INTO chunks (id, skill_id, section_title, content, chunk_index, embedding) VALUES (
  'c683e952-0f65-5a47-9d89-93ebc5016e4a',
  '53189b9e-d3a9-553b-95cb-cdf9a9eb9d62',
  'Application Integration Examples',
  '### Python (psycopg2)

```python
import psycopg2

conn = psycopg2.connect(
    host=''localhost'',
    port=26257,
    user=''root'',
    database=''defaultdb''
)

# Standard query
cursor = conn.cursor()
cursor.execute("SELECT count(*) FROM orders WHERE status = ''pending''")
print(f"Standard: {cursor.fetchone()[0]}")

# Follower read query
cursor.execute("""
    SELECT count(*) FROM orders
    AS OF SYSTEM TIME follower_read_timestamp()
    WHERE status = ''pending''
""")
print(f"Follower: {cursor.fetchone()[0]}")

conn.close()
```

### Java (JDBC)

```java
import java.sql.*;

Connection conn = DriverManager.getConnection(
    "jdbc:postgresql://localhost:26257/defaultdb?sslmode=disable",
    "root", ""
);

// Standard query
Statement stmt = conn.createStatement();
ResultSet rs = stmt.executeQuery(
    "SELECT count(*) FROM orders WHERE status = ''pending''"
);
rs.next();
System.out.println("Standard: " + rs.getInt(1));

// Follower read query
rs = stmt.executeQuery(
    "SELECT count(*) FROM orders " +
    "AS OF SYSTEM TIME follower_read_timestamp() " +
    "WHERE status = ''pending''"
);
rs.next();
System.out.println("Follower: " + rs.getInt(1));

conn.close();
```

### Go (pgx)

```go
package main

import (
    "context"
    "fmt"
    "github.com/jackc/pgx/v5"
)

func main() {
    conn, _ := pgx.Connect(context.Background(),
        "postgresql://root@localhost:26257/defaultdb?sslmode=disable")
    defer conn.Close(context.Background())

    // Standard query
    var count int
    conn.QueryRow(context.Background(),
        "SELECT count(*) FROM orders WHERE status = ''pending''").Scan(&count)
    fmt.Printf("Standard: %d\\n", count)

    // Follower read
    conn.QueryRow(context.Background(),
        `SELECT count(*) FROM orders
         AS OF SYSTEM TIME follower_read_timestamp()
         WHERE status = ''pending''`).Scan(&count)
    fmt.Printf("Follower: %d\\n", count)
}
```',
