INSERT INTO chunks (id, skill_id, section_title, content, chunk_index, embedding) VALUES (
  'f0e46c38-a0ee-55e7-8a42-8bef986f3e5f',
  'b3f1b347-c49c-5ab3-9435-6bc964710599',
  'Common Misconceptions',
  '1. **"Reads can be served from any replica"** - No, only the leaseholder serves reads (except GLOBAL tables)
2. **"Leaseholder and Raft leader are always the same"** - Yes with Leader Leases (v26.1+), but not with deprecated epoch-based leases
3. **"Moving leaseholder is expensive"** - No, lease transfer is lightweight (milliseconds), unlike replica movement
4. **"Leaseholder preferences are instant"** - No, allow 30-60 seconds for lease transfers
5. **"GLOBAL tables have leaseholders everywhere"** - No, they use special read mechanism that bypasses normal leaseholder reads',
